import { useState } from "react";

// ====== DESIGN TOKENS ======
const C = {
  brand:"#1D9E75",brandL:"#E1F5EE",brandD:"#0F6E56",brandDD:"#04342C",
  bg:"#F7F6F3",card:"#FFFFFF",bdr:"rgba(0,0,0,0.07)",
  t1:"#1a1a1a",t2:"#6b6b6b",t3:"#999",
  r:"#E24B4A",rL:"#FCEBEB",rD:"#A32D2D",
  w:"#EF9F27",wL:"#FAEEDA",wD:"#854F0B",
  g:"#639922",gL:"#EAF3DE",gD:"#3B6D11",
  b:"#378ADD",bL:"#E6F1FB",bD:"#185FA5",
  p:"#7F77DD",pL:"#EEEDFE",pD:"#534AB7",
  k:"#D85A30",kL:"#FAECE7",kD:"#993C1D",
  pk:"#D4537E",pkL:"#FBEAF0",pkD:"#993556",
};
const Badge=({children,c="brand",s})=>{const m={brand:[C.brandL,C.brandD],danger:[C.rL,C.rD],warning:[C.wL,C.wD],success:[C.gL,C.gD],info:[C.bL,C.bD],purple:[C.pL,C.pD],gray:["#EDECE8","#5F5E5A"],coral:[C.kL,C.kD],pink:[C.pkL,C.pkD]};const[bg,fg]=m[c]||m.brand;return (<span style={{display:"inline-block",padding:s?"2px 7px":"3px 10px",borderRadius:6,background:bg,color:fg,fontSize:s?9:11,fontWeight:500,lineHeight:1.4,whiteSpace:"nowrap"}}>{children}</span>)};
const Btn=({children,primary,full,sm,ghost})=><div style={{padding:sm?"5px 11px":"9px 16px",borderRadius:8,fontSize:sm?11:13,fontWeight:500,cursor:"pointer",background:primary?C.brand:ghost?"transparent":C.bg,color:primary?"white":ghost?C.b:C.t2,border:ghost?"none":`1px solid ${primary?C.brand:C.bdr}`,width:full?"100%":"auto",textAlign:"center",display:"inline-flex",alignItems:"center",justifyContent:"center",gap:4}}>{children}</div>;
const Input=({ph,w,icon})=><div style={{display:"flex",alignItems:"center",gap:6,background:C.bg,borderRadius:8,padding:"7px 10px",border:`1px solid ${C.bdr}`,flex:1,width:w}}>{icon&&<span style={{fontSize:12,opacity:.4}}>{icon}</span>}<span style={{fontSize:12,color:C.t3}}>{ph}</span></div>;
const Field=({l,ph,v})=><div style={{marginBottom:10}}><div style={{fontSize:10,color:C.t3,marginBottom:4}}>{l}</div><div style={{background:C.bg,borderRadius:6,padding:"7px 10px",fontSize:12,border:`1px solid ${C.bdr}`,color:v?C.t1:C.t3}}>{v||ph}</div></div>;
const Divider=()=><div style={{borderTop:`1px solid ${C.bdr}`,margin:"10px 0"}}/>;
const Section=({t,children})=><div><div style={{fontSize:10,color:C.t3,textTransform:"uppercase",letterSpacing:.5,marginBottom:6,marginTop:14}}>{t}</div>{children}</div>;
const Row=({l,r,b,c})=><div style={{display:"flex",justifyContent:"space-between",padding:"7px 0",borderBottom:b?`1px solid ${C.bdr}`:"none"}}><span style={{fontSize:12,color:C.t2}}>{l}</span><span style={{fontSize:12,fontWeight:b?600:500,color:c||C.t1}}>{r}</span></div>;
const Card=({children,p="12px",mb=8})=><div style={{background:C.card,borderRadius:10,border:`1px solid ${C.bdr}`,padding:p,marginBottom:mb}}>{children}</div>;
const Tile=({ic,l,s,c=C.brand,sm})=><div style={{background:C.card,borderRadius:sm?8:10,padding:sm?"10px":"14px 12px",border:`1px solid ${C.bdr}`,cursor:"pointer"}}><div style={{width:sm?28:36,height:sm?28:36,borderRadius:8,background:`${c}15`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:sm?14:18,color:c,marginBottom:sm?6:10}}>{ic}</div><div style={{fontSize:sm?11:13,fontWeight:600}}>{l}</div>{s&&<div style={{fontSize:10,color:C.t2,marginTop:1}}>{s}</div>}</div>;
const Avatar=({n,sz=32,c=C.brand,bg=C.brandL})=><div style={{width:sz,height:sz,borderRadius:"50%",background:bg,display:"flex",alignItems:"center",justifyContent:"center",fontSize:sz*.35,fontWeight:500,color:c,flexShrink:0}}>{n.split(" ").map(w=>w[0]).join("")}</div>;

// ====== BOTTOM NAV ======
const BottomNav=({active="home"})=><div style={{display:"flex",justifyContent:"space-around",padding:"8px 0 4px",background:C.card,borderTop:`1px solid ${C.bdr}`}}>{[["home","◎","Home"],["pos","◇","POS"],["tasks","≡","Tasks"],["settings","⚙","More"]].map(([k,ic,l])=><div key={k} style={{textAlign:"center",cursor:"pointer"}}><div style={{fontSize:16,color:active===k?C.brand:C.t3}}>{ic}</div><div style={{fontSize:8,color:active===k?C.brand:C.t3,marginTop:1}}>{l}</div></div>)}</div>;

// ====== PHONE FRAME ======
const PF=({children,nav,active})=><div style={{width:375,background:C.bg,borderRadius:28,border:`1px solid ${C.bdr}`,overflow:"hidden",boxShadow:"0 2px 16px rgba(0,0,0,.05)",flexShrink:0,display:"flex",flexDirection:"column"}}><div style={{height:32,background:C.card,display:"flex",alignItems:"center",justifyContent:"center",borderBottom:`1px solid ${C.bdr}`}}><span style={{fontSize:9,color:C.t3,letterSpacing:.5}}>Posterita</span></div><div style={{flex:1,overflowY:"auto",minHeight:500,maxHeight:640}}>{children}</div>{nav!==false&&<BottomNav active={active}/>}</div>;

// ====== PRODUCTS DATA ======
const prods=[{id:1,n:"Reef sandal navy",sku:"RF-2847",pr:1290,cat:"Footwear",cl:"#2563eb"},{id:2,n:"Canvas tote natural",sku:"CT-0412",pr:650,cat:"Bags",cl:"#d97706"},{id:3,n:"Flip flop coral M",sku:"FF-1039",pr:490,cat:"Footwear",cl:"#e11d48"},{id:4,n:"Beach hat straw",sku:"BH-0876",pr:380,cat:"Accessories",cl:"#ca8a04"},{id:5,n:"Dive mask pro",sku:"DM-1455",pr:2150,cat:"Gear",cl:"#0891b2"},{id:6,n:"Board shorts blue L",sku:"BS-3321",pr:890,cat:"Apparel",cl:"#4f46e5"},{id:7,n:"Surf rash guard",sku:"SR-2209",pr:1450,cat:"Apparel",cl:"#7c3aed"},{id:8,n:"Snorkel set kids",sku:"SK-0087",pr:780,cat:"Gear",cl:"#059669"},{id:9,n:"Slide sandal black",sku:"SS-4412",pr:590,cat:"Footwear",cl:"#374151"},{id:10,n:"Waterproof pouch",sku:"WP-1678",pr:320,cat:"Accessories",cl:"#0d9488"},{id:11,n:"Reef sandal tan",sku:"RF-2901",pr:1290,cat:"Footwear",cl:"#92400e"},{id:12,n:"Mesh backpack",sku:"MB-0534",pr:750,cat:"Bags",cl:"#6b21a8"}];
const cats=["All","Footwear","Bags","Accessories","Gear","Apparel"];
const cartItems=[{...prods[0],qty:1},{...prods[1],qty:2},{...prods[2],qty:1}];
const cartTotal=cartItems.reduce((s,i)=>s+i.pr*i.qty,0);

const ProdThumb=({p,compact})=><div style={{background:C.card,borderRadius:compact?6:8,border:`1px solid ${C.bdr}`,padding:compact?6:10,cursor:"pointer"}}><div style={{width:"100%",aspectRatio:"1",borderRadius:compact?4:6,background:`${p.cl}12`,display:"flex",alignItems:"center",justifyContent:"center",marginBottom:compact?4:6}}><div style={{width:compact?20:28,height:compact?20:28,borderRadius:"50%",background:`${p.cl}25`,border:`2px solid ${p.cl}40`}}/></div><div style={{fontSize:compact?10:11,fontWeight:500,lineHeight:1.2}}>{p.n}</div><div style={{fontSize:compact?8:9,color:C.t3}}>{p.sku}</div><div style={{fontSize:compact?11:13,fontWeight:600,color:C.brand,marginTop:2}}>Rs {p.pr.toLocaleString()}</div></div>;

