const MWelcome=()=><PF nav={false}><div style={{padding:"80px 24px",textAlign:"center"}}><div style={{width:80,height:80,borderRadius:20,background:C.brandL,margin:"0 auto 24px",display:"flex",alignItems:"center",justifyContent:"center"}}><div style={{fontSize:32,fontWeight:700,color:C.brand}}>P</div></div><div style={{fontSize:22,fontWeight:600,marginBottom:4}}>Posterita</div><div style={{fontSize:13,color:C.t2,marginBottom:40}}>Unified retail operations</div><div style={{marginBottom:12}}><Btn primary full>Get started</Btn></div><div style={{fontSize:12,color:C.b,cursor:"pointer"}}>I have an account — log in</div></div></PF>;

const MPhoneEntry=()=><PF nav={false}><div style={{padding:"40px 24px"}}><div style={{fontSize:18,fontWeight:600,marginBottom:4}}>Enter your phone number</div><div style={{fontSize:12,color:C.t2,marginBottom:24}}>We'll send you a verification code via WhatsApp</div><div style={{display:"flex",gap:8,marginBottom:8}}><div style={{background:C.bg,borderRadius:8,padding:"10px 12px",border:`1px solid ${C.bdr}`,fontSize:14,color:C.t1}}>+230</div><div style={{flex:1,background:C.bg,borderRadius:8,padding:"10px 12px",border:`1px solid ${C.bdr}`,fontSize:14,color:C.t3}}>5XXX XXXX</div></div><div style={{fontSize:10,color:C.t3,marginBottom:24}}>We'll use WhatsApp to send your OTP</div><Btn primary full>Send code</Btn></div></PF>;

