const MProfileSetup=()=><PF nav={false}><div style={{padding:"24px 20px"}}><div style={{fontSize:18,fontWeight:600,marginBottom:4}}>Set up your profile</div><div style={{fontSize:12,color:C.t2,marginBottom:20}}>This info helps your team identify you</div><div style={{textAlign:"center",marginBottom:20}}><div style={{width:72,height:72,borderRadius:"50%",background:C.brandL,margin:"0 auto 8px",display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,color:C.brand}}>📷</div><div style={{fontSize:11,color:C.b}}>Add photo</div></div><Field l="First name" ph="Enter first name" v="Sarah"/><Field l="Last name" ph="Enter last name" v="Martin"/><Field l="Emergency contact name" ph="Who to contact in emergency"/><Field l="Emergency contact phone" ph="+230 XXXX XXXX"/><div style={{marginTop:16}}><Btn primary full>Continue</Btn></div></div></PF>;

const MPINSetup=()=><PF nav={false}><div style={{padding:"40px 24px",textAlign:"center"}}><div style={{fontSize:18,fontWeight:600,marginBottom:4}}>Create your PIN</div><div style={{fontSize:12,color:C.t2,marginBottom:32}}>4-digit PIN for daily login</div><div style={{display:"flex",justifyContent:"center",gap:12,marginBottom:32}}>{[1,2,0,0].map((d,i)=><div key={i} style={{width:14,height:14,borderRadius:"50%",background:i<2?C.brand:C.bdr}}/>)}</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10,maxWidth:220,margin:"0 auto"}}>{[1,2,3,4,5,6,7,8,9,"",0,"⌫"].map((n,i)=><div key={i} style={{width:52,height:52,borderRadius:12,background:n!==""?C.card:"transparent",border:n!==""?`1px solid ${C.bdr}`:"none",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,fontWeight:500,cursor:"pointer",margin:"0 auto"}}>{n}</div>)}</div></div></PF>;

const MEnroll=()=><PF nav={false}><div style={{padding:"32px 20px",textAlign:"center"}}><div style={{fontSize:18,fontWeight:600,marginBottom:4}}>Enroll this device</div><div style={{fontSize:12,color:C.t2,marginBottom:24}}>Ask your supervisor for the QR code</div><div style={{width:200,height:200,borderRadius:16,border:`2px dashed ${C.brand}50`,margin:"0 auto 20px",display:"flex",alignItems:"center",justifyContent:"center",background:`${C.brand}08`}}><div style={{textAlign:"center"}}><div style={{fontSize:40,marginBottom:4,opacity:.3}}>📷</div><div style={{fontSize:11,color:C.t3}}>Point camera at QR</div></div></div><div style={{background:C.bL,borderRadius:8,padding:"10px 14px",textAlign:"left"}}><div style={{fontSize:10,fontWeight:500,color:C.bD}}>This will:</div><div style={{fontSize:10,color:C.bD,opacity:.8,lineHeight:1.6,marginTop:4}}>• Link device to your store<br/>• Download capability profile<br/>• Sync product catalog</div></div></div></PF>;

const MLogin=()=><PF nav={false}><div style={{padding:"50px 24px",textAlign:"center"}}><div style={{width:56,height:56,borderRadius:14,background:C.brandL,margin:"0 auto 16px",display:"flex",alignItems:"center",justifyContent:"center"}}><div style={{fontSize:22,fontWeight:700,color:C.brand}}>P</div></div><div style={{fontSize:18,fontWeight:600,marginBottom:2}}>Welcome back, Sarah</div><div style={{fontSize:12,color:C.t2,marginBottom:28}}>Enter your PIN</div><div style={{display:"flex",justifyContent:"center",gap:12,marginBottom:28}}>{[1,2,3,4].map(i=><div key={i} style={{width:12,height:12,borderRadius:"50%",background:i<=2?C.brand:C.bdr}}/>)}</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10,maxWidth:220,margin:"0 auto"}}>{[1,2,3,4,5,6,7,8,9,"",0,"⌫"].map((n,i)=><div key={i} style={{width:52,height:52,borderRadius:12,background:n!==""?C.card:"transparent",border:n!==""?`1px solid ${C.bdr}`:"none",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,fontWeight:500,cursor:"pointer",margin:"0 auto"}}>{n}</div>)}</div><div style={{marginTop:20,fontSize:11,color:C.b}}>Use biometric</div></div></PF>;

