const MHome=()=><PF active="home"><div style={{padding:"16px 14px"}}><div style={{fontSize:17,fontWeight:600}}>Good morning, Sarah</div><div style={{fontSize:11,color:C.t2,marginTop:2,marginBottom:14}}>Grand Baie · Cashier + Supervisor</div><div style={{background:C.brandL,borderRadius:10,padding:"10px 12px",marginBottom:14,display:"flex",alignItems:"center",gap:10}}><div style={{width:30,height:30,borderRadius:8,background:C.brand,display:"flex",alignItems:"center",justifyContent:"center",color:"white",fontSize:13,fontWeight:600}}>3</div><div><div style={{fontSize:11,fontWeight:500,color:C.brandD}}>Pending approvals</div><div style={{fontSize:9,color:C.brandD,opacity:.7}}>2 leave · 1 expense</div></div></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:14}}><Tile ic="◎" l="POS" s="Point of sale" c={C.brand}/><Tile ic="≡" l="Staff ops" s="Daily tasks" c={C.b}/><Tile ic="✓" l="Supervisor" s="Approvals" c={C.p}/><Tile ic="▦" l="Inventory" s="Stock & counts" c={C.w}/></div><Card><div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}><span style={{fontSize:10,fontWeight:500,color:C.t2}}>Today's summary</span><Badge c="success" s>Synced</Badge></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6}}>{[["47","Orders"],["Rs 84k","Revenue"],["12","Loyalty"]].map(([v,l],i)=><div key={i}><div style={{fontSize:14,fontWeight:600}}>{v}</div><div style={{fontSize:9,color:C.t3}}>{l}</div></div>)}</div></Card></div></PF>;

const MNotifications=()=><PF active="home"><div style={{padding:"16px 14px"}}><div style={{fontSize:16,fontWeight:600,marginBottom:14}}>Notifications</div>{[{t:"Leave approved",d:"Your annual leave 22–24 Apr was approved by Amina K.",time:"10m ago",c:"success"},{t:"New task assigned",d:"Restock sandal display — due by 12:00",time:"25m ago",c:"info"},{t:"Till discrepancy flagged",d:"Grand Baie shift 08:00–16:30: -Rs 1,240",time:"1h ago",c:"danger"},{t:"Sync complete",d:"47 orders pushed, 12 products pulled",time:"2h ago",c:"brand"},{t:"Device heartbeat warning",d:"POS-CP-01 not responding for 47 minutes",time:"3h ago",c:"warning"},{t:"Expense claim rejected",d:"Transport Rs 340 — missing receipt",time:"5h ago",c:"danger"}].map((n,i)=><Card key={i}><div style={{display:"flex",gap:8}}><div style={{width:8,height:8,borderRadius:"50%",background:C[n.c]||C.brand,marginTop:4,flexShrink:0}}/><div><div style={{fontSize:12,fontWeight:500}}>{n.t}</div><div style={{fontSize:11,color:C.t2,lineHeight:1.4,marginTop:2}}>{n.d}</div><div style={{fontSize:9,color:C.t3,marginTop:4}}>{n.time}</div></div></div></Card>)}</div></PF>;

// ---- POS FLOW ----
const MProdGrid=()=>{const[cat,setCat]=useState("All");const f=cat==="All"?prods:prods.filter(p=>p.cat===cat);return<PF active="pos"><div style={{display:"flex",flexDirection:"column",height:"100%"}}><div style={{padding:"8px 12px 0",background:C.card,borderBottom:`1px solid ${C.bdr}`}}><div style={{display:"flex",gap:6,marginBottom:6}}><Input ph="Search or scan..." icon="🔍"/><div style={{width:36,height:36,borderRadius:8,background:C.brand,display:"flex",alignItems:"center",justifyContent:"center",color:"white",fontSize:14,flexShrink:0}}>▤</div></div><div style={{display:"flex",gap:4,overflowX:"auto",paddingBottom:8}}>{cats.map(c=><span key={c} onClick={()=>setCat(c)} style={{padding:"3px 9px",borderRadius:12,fontSize:10,cursor:"pointer",whiteSpace:"nowrap",background:cat===c?C.brandL:"transparent",color:cat===c?C.brandD:C.t3,fontWeight:cat===c?500:400,border:`1px solid ${cat===c?C.brand+"40":"transparent"}`}}>{c}</span>)}</div></div><div style={{flex:1,overflowY:"auto",padding:8}}><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6}}>{f.map(p=><ProdThumb key={p.id} p={p} compact/>)}</div></div><div style={{padding:"8px 12px",background:C.card,borderTop:`1px solid ${C.bdr}`,display:"flex",alignItems:"center",justifyContent:"space-between"}}><div><span style={{fontSize:11,color:C.t2}}>Cart: </span><span style={{fontSize:12,fontWeight:600}}>3 items · Rs {cartTotal.toLocaleString()}</span></div><Btn primary sm>Checkout →</Btn></div></div></PF>};

const MProdDetail=()=><PF active="pos"><div style={{padding:"16px 14px"}}><div style={{width:"100%",height:200,borderRadius:12,background:`${prods[0].cl}12`,display:"flex",alignItems:"center",justifyContent:"center",marginBottom:14}}><div style={{width:60,height:60,borderRadius:"50%",background:`${prods[0].cl}25`,border:`3px solid ${prods[0].cl}40`}}/></div><div style={{fontSize:18,fontWeight:600,marginBottom:2}}>{prods[0].n}</div><div style={{fontSize:12,color:C.t3,marginBottom:8}}>SKU: {prods[0].sku} · Category: {prods[0].cat}</div><div style={{fontSize:22,fontWeight:700,color:C.brand,marginBottom:16}}>Rs {prods[0].pr.toLocaleString()}</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:16}}><div style={{background:C.bg,borderRadius:8,padding:10}}><div style={{fontSize:10,color:C.t3}}>In stock</div><div style={{fontSize:14,fontWeight:600}}>24</div></div><div style={{background:C.bg,borderRadius:8,padding:10}}><div style={{fontSize:10,color:C.t3}}>Sold today</div><div style={{fontSize:14,fontWeight:600}}>3</div></div></div><Field l="Barcode" v="4006381 903284"/><Field l="VAT" v="15% standard rate"/><div style={{display:"flex",gap:8,marginTop:12}}><Btn full>Add to cart</Btn><Btn primary full>Quick sale</Btn></div></div></PF>;

