const MAIPhone=()=><PF active="tasks"><div style={{padding:"16px 14px"}}><div style={{fontSize:15,fontWeight:600,marginBottom:4}}>AI tasks</div><div style={{fontSize:11,color:C.t2,marginBottom:12}}>Agent activity on your store</div>{[{t:"Daily summary generated",g:"Auto",s:"Done",c:"success"},{t:"Restock tasks assigned",g:"Auto",s:"Done",c:"success"},{t:"Warning for late arrivals",g:"Needs approval",s:"Pending",c:"warning"},{t:"Shift schedule drafted",g:"Auto",s:"Done",c:"success"}].map((t,i)=><Card key={i} p="10px"><div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><div><div style={{fontSize:11,fontWeight:500}}>{t.t}</div><div style={{fontSize:9,color:C.t3}}>{t.g}</div></div><Badge c={t.c} s>{t.s}</Badge></div>{t.s==="Pending"&&<div style={{display:"flex",gap:4,marginTop:6}}><div style={{padding:"3px 10px",borderRadius:4,background:C.gL,color:C.gD,fontSize:10,cursor:"pointer"}}>Approve</div><div style={{padding:"3px 10px",borderRadius:4,background:C.rL,color:C.rD,fontSize:10,cursor:"pointer"}}>Reject</div></div>}</Card>)}</div></PF>;

