const TF=({children})=><div style={{width:"100%",minHeight:580,background:C.bg,borderRadius:14,border:`1px solid ${C.bdr}`,overflow:"hidden",boxShadow:"0 2px 16px rgba(0,0,0,.05)"}}>{children}</div>;

const TabPOS=()=><TF><div style={{display:"flex",height:580}}><div style={{flex:1,display:"flex",flexDirection:"column",borderRight:`1px solid ${C.bdr}`}}><div style={{padding:"10px 14px",background:C.card,borderBottom:`1px solid ${C.bdr}`}}><div style={{display:"flex",gap:8,marginBottom:6}}><Input ph="Search product or scan barcode..." icon="🔍"/><div style={{width:40,height:36,borderRadius:8,background:C.brand,display:"flex",alignItems:"center",justifyContent:"center",color:"white",fontSize:14,flexShrink:0}}>▤</div></div><div style={{display:"flex",gap:4}}>{cats.map(c=><span key={c} style={{padding:"4px 10px",borderRadius:12,fontSize:11,background:c==="All"?C.brandL:"transparent",color:c==="All"?C.brandD:C.t3,fontWeight:c==="All"?500:400,border:`1px solid ${c==="All"?C.brand+"40":"transparent"}`,cursor:"pointer"}}>{c}</span>)}</div></div><div style={{flex:1,overflowY:"auto",padding:10}}><div style={{display:"grid",gridTemplateColumns:"repeat(4, 1fr)",gap:8}}>{prods.map(p=><ProdThumb key={p.id} p={p}/>)}</div></div></div><div style={{width:320,background:C.card,display:"flex",flexDirection:"column"}}><div style={{padding:"10px 12px",borderBottom:`1px solid ${C.bdr}`,display:"flex",justifyContent:"space-between",alignItems:"center"}}><span style={{fontSize:13,fontWeight:600}}>Cart</span><Badge c="purple" s>Marie L. · 420 pts</Badge></div><div style={{flex:1,overflowY:"auto",padding:"8px 10px"}}><div style={{fontSize:9,color:C.t3,textTransform:"uppercase",marginBottom:4}}>3 items</div>{cartItems.map((it,i)=><Card key={i} p="8px" mb={4}><div style={{display:"flex",alignItems:"center",gap:6}}><div style={{width:28,height:28,borderRadius:4,background:`${it.cl}12`}}/><div style={{flex:1,minWidth:0}}><div style={{fontSize:10,fontWeight:500,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{it.n}</div><div style={{fontSize:8,color:C.t3}}>{it.sku}</div></div><div style={{display:"flex",alignItems:"center",gap:3,background:C.bg,borderRadius:3,padding:"1px 4px"}}><span style={{fontSize:10,color:C.t3}}>−</span><span style={{fontSize:10,fontWeight:500}}>{it.qty}</span><span style={{fontSize:10,color:C.t3}}>+</span></div><div style={{fontSize:11,fontWeight:600,minWidth:44,textAlign:"right"}}>Rs {(it.pr*it.qty).toLocaleString()}</div></div></Card>)}<div style={{background:C.pL,borderRadius:6,padding:"6px 8px",marginTop:4}}><div style={{fontSize:9,fontWeight:500,color:C.pD}}>Loyalty: +{Math.round(cartTotal/100)} pts → Marie L.</div></div></div><div style={{borderTop:`1px solid ${C.bdr}`,padding:"10px"}}><Row l="Subtotal" r={`Rs ${cartTotal.toLocaleString()}`} b/><Row l="VAT 15%" r={`Rs ${Math.round(cartTotal*.15).toLocaleString()}`} b/><div style={{display:"flex",justifyContent:"space-between",padding:"6px 0 8px"}}><span style={{fontSize:14,fontWeight:600}}>Total</span><span style={{fontSize:14,fontWeight:600}}>Rs {Math.round(cartTotal*1.15).toLocaleString()}</span></div><div style={{display:"flex",gap:6}}><Btn full sm>Cash</Btn><Btn primary full sm>Card / Blink</Btn></div></div></div></div></TF>;

const TabSupervisor=()=><TF><div style={{display:"flex",height:580}}><div style={{width:200,background:"#FAFAF8",borderRight:`1px solid ${C.bdr}`,padding:"12px 0"}}><div style={{padding:"0 12px 10px",fontWeight:600,fontSize:12,color:C.brand}}>Supervisor</div>{["Approvals","Shifts","Tasks","Checklist","Warnings","Reports"].map((n,i)=><div key={n} style={{padding:"6px 12px",fontSize:11,color:i===0?C.brand:C.t2,background:i===0?C.brandL:"transparent",fontWeight:i===0?500:400,cursor:"pointer"}}>{n}</div>)}</div><div style={{flex:1,padding:"14px 18px",overflowY:"auto"}}><div style={{display:"flex",justifyContent:"space-between",marginBottom:14}}><div style={{fontSize:15,fontWeight:600}}>Pending approvals</div><div style={{display:"flex",gap:6}}><Badge c="info">3 Leave</Badge><Badge c="warning">2 Expense</Badge><Badge c="danger">1 Recon</Badge></div></div>{[{w:"Ravi P.",ty:"Annual leave",d:"22–26 Apr · 5 days",det:"Leave balance: 12 days remaining"},{w:"Amina K.",ty:"Expense claim",d:"Rs 2,400 · Transport receipts attached",det:"Policy: up to Rs 5,000 auto-approvable"},{w:"Jean-Luc M.",ty:"Sick leave",d:"Today · Doctor's note attached",det:"3rd sick day this quarter"},{w:"Sarah M.",ty:"Reconciliation",d:"Discrepancy: - Rs 1,240 · Grand Baie",det:"Cashier note: 'Cash/card processing error'"}].map((a,i)=><Card key={i} p="14px"><div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}><div><div style={{fontSize:12,fontWeight:500}}>{a.w} · {a.ty}</div><div style={{fontSize:10,color:C.t3}}>{a.d}</div><div style={{fontSize:10,color:C.t2,marginTop:2}}>{a.det}</div></div></div><div style={{display:"flex",gap:6,marginTop:8}}><Btn sm primary>Approve</Btn><Btn sm>Reject</Btn><Btn sm>View details</Btn></div></Card>)}</div></div></TF>;

